1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	};
11	
12	const basePremiumFor = (items: { type: string }[]): number =>
13	  items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
14	
15	const quotePremium = (base: number): number =>
16	  Math.ceil(base + base * FIRST_INSURANCE_RATE + PROCESSING_FEE);
17	
18	export const runScenario = (scenario: any): unknown => {
19	  const base = basePremiumFor(scenario.steps[0].items);
20	  return { results: [{ premium: quotePremium(base) }] };
21	};
